import subprocess
from pathlib import Path

APP = Path("/app")
M1_CONTRACT = Path("/steps/milestone_1/tests/milestone_1_contract_test.go")

FILES = {
    "internal/dispatch/milestone_1_contract_test.go": M1_CONTRACT.read_text(encoding="utf-8"),
    'internal/dispatch/milestone_2_contract_test.go': 'package dispatch\n\nimport (\n    "context"\n    "errors"\n    "fmt"\n    "sync"\n    "sync/atomic"\n    "testing"\n    "time"\n)\n\nfunc TestShutdownCancelsInFlightAndIsRepeatable(t *testing.T) {\n    started := make(chan struct{})\n    var finished atomic.Bool\n    var once sync.Once\n    d := NewDispatcher(2, func(ctx context.Context, job Job) error {\n        once.Do(func() { close(started) })\n        <-ctx.Done()\n        finished.Store(true)\n        return ctx.Err()\n    })\n    if err := d.Enqueue(Job{OperationKey: "shutdown-op"}); err != nil {\n        t.Fatalf("enqueue: %v", err)\n    }\n    select {\n    case <-started:\n    case <-time.After(time.Second):\n        t.Fatal("delivery did not start")\n    }\n\n    ctx, cancel := context.WithTimeout(context.Background(), 250*time.Millisecond)\n    defer cancel()\n    if err := d.Shutdown(ctx); err != nil {\n        t.Fatalf("first shutdown: %v", err)\n    }\n    if !finished.Load() {\n        t.Fatal("in-flight delivery still running after Shutdown returned")\n    }\n\n    again, cancelAgain := context.WithTimeout(context.Background(), 50*time.Millisecond)\n    defer cancelAgain()\n    if err := d.Shutdown(again); err != nil {\n        t.Fatalf("repeat shutdown: %v", err)\n    }\n    if got := d.QueueDepth(); got != 0 {\n        t.Fatalf("queue depth after shutdown = %d, want 0", got)\n    }\n}\n\nfunc TestEnqueueRejectedAfterShutdown(t *testing.T) {\n    d := NewDispatcher(1, func(context.Context, Job) error { return nil })\n    ctx, cancel := context.WithTimeout(context.Background(), 250*time.Millisecond)\n    defer cancel()\n    if err := d.Shutdown(ctx); err != nil {\n        t.Fatalf("shutdown: %v", err)\n    }\n    started := time.Now()\n    err := d.Enqueue(Job{OperationKey: "late-op"})\n    if err == nil {\n        t.Fatal("enqueue after shutdown succeeded")\n    }\n    if time.Since(started) > 50*time.Millisecond {\n        t.Fatalf("post-shutdown enqueue blocked for %s", time.Since(started))\n    }\n}\n\nfunc TestEnqueueRacingShutdownNeverPanicsOrHangs(t *testing.T) {\n    d := NewDispatcher(2, func(ctx context.Context, job Job) error {\n        select {\n        case <-ctx.Done():\n            return ctx.Err()\n        case <-time.After(10 * time.Millisecond):\n            return nil\n        }\n    })\n\n    var wg sync.WaitGroup\n    errCh := make(chan error, 80)\n    for i := 0; i < 80; i++ {\n        wg.Add(1)\n        go func(i int) {\n            defer wg.Done()\n            errCh <- d.Enqueue(Job{OperationKey: fmt.Sprintf("race-%d", i)})\n        }(i)\n    }\n    time.Sleep(5 * time.Millisecond)\n    shutdownCtx, cancel := context.WithTimeout(context.Background(), 500*time.Millisecond)\n    defer cancel()\n    if err := d.Shutdown(shutdownCtx); err != nil {\n        t.Fatalf("shutdown during producer race: %v", err)\n    }\n\n    done := make(chan struct{})\n    go func() { wg.Wait(); close(done) }()\n    select {\n    case <-done:\n    case <-time.After(time.Second):\n        t.Fatal("enqueue calls remained blocked after shutdown")\n    }\n    close(errCh)\n    for err := range errCh {\n        if err != nil && !errors.Is(err, ErrStopped) && !errors.Is(err, context.Canceled) {\n            t.Fatalf("unexpected enqueue error: %v", err)\n        }\n    }\n    if got := d.QueueDepth(); got != 0 {\n        t.Fatalf("queue depth after raced shutdown = %d, want 0", got)\n    }\n}\n\nfunc TestShutdownReturnsDeadlineErrorWhenWorkersHang(t *testing.T) {\n    d := NewDispatcher(1, func(ctx context.Context, job Job) error {\n        time.Sleep(2 * time.Second)\n        return nil\n    })\n    if err := d.Enqueue(Job{OperationKey: "slow-shutdown-op"}); err != nil {\n        t.Fatalf("enqueue slow job: %v", err)\n    }\n    time.Sleep(10 * time.Millisecond)\n    ctx, cancel := context.WithTimeout(context.Background(), 20*time.Millisecond)\n    defer cancel()\n    err := d.Shutdown(ctx)\n    if !errors.Is(err, context.DeadlineExceeded) {\n        t.Fatalf("shutdown error = %v, want DeadlineExceeded", err)\n    }\n}\n'}

def test_go_contracts():
    for relative, content in FILES.items():
        path = APP / relative
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8")
    result = subprocess.run(
        ["/usr/local/go/bin/go", "test", "-race", "./internal/dispatch", "./internal/delivery", "./internal/idempotency", "-count=1"],
        cwd=APP,
        capture_output=True,
        text=True,
        timeout=120,
    )
    assert result.returncode == 0, result.stdout + result.stderr
